      if (value === null) {
        callback();
      } else if (isNaN(value)) {//true为字符串
        callback(new Error('请输入数字值'));
      } else if (value < 0) {
        callback(new Error('请输入非负数'));
      } else if ((value.toString().length - value.toString().indexOf(".") - 1) > 4) {//true为小数位大于4的小数
