  methods: {
    onSubmit() {
      this.$refs["inputForm"].validate((valid) => {
        if (valid) {//表单验证通过开始计算
          //tab禁用解除
          this.tabDisabled = false;

          //输出齿比数组，从小到大
          this.putIArr();

          //输入RatioChart到echars对象
          this.putRatioChart();

          //输入RPMUSeries到echars对象
          this.putRPMUChart(0);

          //输入PSSeries到echars对象
          this.putPSURPMChart();

          //输入PUSeries到echars对象
          this.putPUChart();

          //控制台打印输入的数据
          this.dataShow();

          //在容器中绘制图表
          this.drawPlot()
          // setTimeout(() => this.drawPlot(), 600)//延时输出

        }
      });

    },
    handleClick() {
      this.resDiv();
    },
    slopeArr2Fun() {
      this.slopeArr2 = [];
      let slope = -0.1;
      let step = 0;
      let slopeObjArr = [];
      while (Math.round(slope * 100) / 100 <= 0.1) {
        let obj = {
          value: Math.round(slope * 1000) / 1000,
          symbol: null,
          symbolSize: null
        }
        if (step++ % 5 == 0) {
          obj.symbol = 'diamond',
            obj.symbolSize = 7

        } else {
          obj.symbol = 'circle',
            obj.symbolSize = 3
        }
        slopeObjArr.push(obj)
        slope += 0.01
      }

      for (let key in slopeObjArr) {
        this.slopeArr2.push(slopeObjArr[key].value);
      }
      this.PUPlot.timeline.data = slopeObjArr;
    },
    drawPlot() {
      // 绘制图表
      this.ratioChart.setOption(this.ratioPlot, true);
      this.RPMUChart.setOption(this.RPMUPlot, true);
      this.PSChart.setOption(this.PSURPMPlot, true);
      this.PUChart.setOption(this.PUPlot, true);
    },

    //数据显示
    dataShow() {
      console.log("cda = " + this.cda);
      console.log("flywheelArr = " + this.form.flywheelArr);
      console.log("iArr = " + this.iArr);
      console.log("driveDisk = " + this.form.driveDisk);
      console.log("wheel = " + this.form.wheel);
      console.log("quality = " + this.form.quality);
      console.log("stepFrequency = " + this.form.stepFrequency);
      console.log("minRPM = " + this.minRPM);
      console.log("maxRPM = " + this.maxRPM);
      console.log("comfortMinRPM = " + this.comfortMinRPM);
      console.log("comfortMaxRPM = " + this.comfortMaxRPM);
      console.log("slopeArr2 = " + this.slopeArr2);
    },
    putRatioChart() {
      this.ratioPlot.xAxis.data = null;
      this.ratioPlot.series = [];

      let category = [];
      for (let i = this.form.flywheelArr.length - 1; i >= 0; i--) {
        category.push(this.form.flywheelArr[i] + 'T')
      }

      this.ratioPlot.xAxis.data = category;
      if (typeof this.form.driveDisk == 'string') {
        for (let i = 0; i < this.iArr.length; i++) {
          this.ratioPlot.series[this.iArr.length - 1 - i] = {
            name: this.form.driveDisk.split('-')[this.iArr.length - 1 - i] + 'T',
            type: 'line',
            showSymbol: true,
            clip: true,
            showBackgroud: true,
            backgroudStyle: {
              color: 'rgba(180,180,180,0.2)'
            },
            data: this.iArr[i]
          }
        }
      } else {
        this.ratioPlot.series[0] = {
          name: this.form.driveDisk + 'T',
          type: 'line',
          showSymbol: true,
          clip: true,
          showBackgroud: true,
          backgroudStyle: {
            color: 'rgba(180,180,180,0.2)'
          },
          data: this.iArr[0]
        }
      }

    },
