              },
              {
                yAxis: this.comfortMaxRPM
              }
            ],
          ]
        },
      }


      for (let i = 0; i < this.form.flywheelArr.length; i++) {
        let seri = {
          type: 'line',
          name: this.form.flywheelArr[this.form.flywheelArr.length - 1 - i] + 'T',
          showSymbol: false,
          showName: true,
          clip: true,
          data: this.putRPMUData(this.iArr[num][i]),
        }
        this.RPMUPlot.series.push(seri)
      }
      this.RPMUPlot.series.push(markLine);
      this.RPMUPlot.series.push(markArea);
    },

    putPSURPMChart() {
      this.PSURPMPlot.xAxis[0].data = [];
      this.PSURPMPlot.xAxis[1].data = [];
      this.PSURPMPlot.series = [];

      let arr = [];
      let xArr = [];
      let x1Arr = [];
      for (let i = this.slopeArr.length - 1; i > 0; i--) {
        arr = this.putPSURPMData(this.iArr[0][0], this.slopeArr[i]);
        let yArr = [];
        for (let i = 0; i < arr.length; i++) {
          yArr.push(arr[i][2]);
        }

        let seri = {
          type: 'line',
          name: this.slopeArr[i] * 100 + '%',
          showSymbol: false,
          clip: true,
          data: yArr,
          xAxisIndex: 0,
        }
        this.PSURPMPlot.series.push(seri)
      }
      for (let i = 0; i < arr.length; i++) {
        xArr.push(arr[i][0]);
        x1Arr.push(arr[i][1]);

      }
      this.PSURPMPlot.xAxis[0].data = xArr;
      this.PSURPMPlot.xAxis[1].data = x1Arr;

    },

    putPUChart() {
      this.PUPlot.series = [];
      this.PUPlot.options = new Array(this.slopeArr2.length);
      for (let i = 0; i < this.PUPlot.options.length; i++) {
        this.PUPlot.options[i] = { series: [] };
      }


      //添加到serise
      for (let i = 0; i < this.cda.length; i++) {
        let seri = {
          type: 'line',
          name: this.cda[i][0],
          showSymbol: false,
          showName: true,
          clip: true,
          data: this.putPUData(this.cda[i][1], this.slopeArr2[0]),
        }
        this.PUPlot.series.push(seri)
      }
      //车轮和轴承滚阻
      let seri0 = {
        type: 'line',
        name: '滚阻',
        showSymbol: false,
        color: 'rgb(180,180,180)',
        showName: true,
        areaStyle: {
          opacity: 0.4
        },
        clip: true,
        data: this.putPrrPwbUData(),
      }
      this.PUPlot.series.push(seri0)

      //添加options
      for (let j = 0; j < this.slopeArr2.length; j++) {
        for (let i = 0; i < this.cda.length; i++) {
          let seri = {
            type: 'line',
            name: this.cda[i][0],
            showSymbol: false,
            showName: true,
            clip: true,
            data: this.putPUData(this.cda[i][1], this.slopeArr2[j]),
          }
          this.PUPlot.options[j].series.push(seri)
        }
        //车轮和轴承滚阻
        let seri0 = {
          type: 'line',
          name: '滚阻',
          showSymbol: false,
          color: 'rgb(180,180,180)',
          showName: true,
          areaStyle: {
            opacity: 0.4
          },
          clip: true,
          data: this.putPrrPwbUData(),
        }
        this.PUPlot.options[j].series.push(seri0)

      }


    },



    //输出该车的齿比数组，从小到大（齿比为牙盘齿数比飞轮齿数）
    putIArr() {
      let driveDiskArr;
      let arr = new Array();
      if (typeof this.form.driveDisk == 'string') {
        driveDiskArr = this.form.driveDisk.split('-');
        for (let i = 0; i < driveDiskArr.length; i++) {
          arr[i] = new Array();
          for (let j = 0; j < this.form.flywheelArr.length; j++) {
            arr[i][j] = Math.round(driveDiskArr[driveDiskArr.length - 1 - i] / this.form.flywheelArr[this.form.flywheelArr.length - 1 - j] * 100) / 100;
          }
        }
      } else {
        arr[0] = new Array();
        for (let j = 0; j < this.form.flywheelArr.length; j++) {
          arr[0][j] = Math.round(this.form.driveDisk / this.form.flywheelArr[this.form.flywheelArr.length - 1 - j] * 100) / 100;
        }
      }
      this.iArr = arr;
    },

    //车轮转速和车速的关系，N为车轮转速，U为车速
    putNU(u) {
      let n = u / (this.form.wheel * 0.001 * 3.6)
      return n;
    },
    //一定齿比条件下，踏频和车轮转速的关系，i为齿比，N为车轮转速，PRM为踏频
    putRPMN(n, i) {
      let rpm = n * 60 / i;
      return rpm;
    },
    //一定齿比下，车速和踏频的关系
    putURPM(rpm, i) {
      let u = 3.6 * (rpm / 60) * i * this.form.wheel * 0.001
      return u;
    },
    //一定齿比下，踏频和车速的关系
    putRPMU(u, i) {
      let rpm = u * 60 / (3.6 * i * this.form.wheel * 0.001)
      return rpm;
    },
    //一定齿比和坡度的条件下，功率和踏频的关系
    putPRPM(i, s, rpm) {
      let p = (s * this.putURPM(rpm, i) * this.g * this.form.quality) / (this.form.ec * 3.6) + this.putPU(this.putURPM(rpm, i), this.cda[0][1], 0);
      return p;
    },
    //某齿比下的最低车速
    putUMin(i) {
      let umin = this.putURPM(this.minRPM, i)
      return umin;
    },
    //某齿比下的最高车速
    putUMax(i) {
      let uMax = this.putURPM(this.maxRPM, i)
      return uMax;
    },
    //滚动阻力、轴承阻力功率
    putPrrPwbU(u) {
      let prr = this.form.mu * this.form.quality * this.g * u / 3.6;//滚动阻力
      let pwb = (91 + 8.7 * u / 3.6) * u / 3.6 * 0.001;//车轮轴承阻力
      return prr + pwb;
    },
    //重力做功功率
    putPpeSU(s, u) {
      let Ppe = (s * u * this.g * this.form.quality) / 3.6
      return Ppe;
    },
    //空气阻力功率
    putPatU(cda, u) {
      let pat = 0.5 * this.rho * (cda + this.fw) * Math.pow(u / 3.6, 3) * this.factor;
      return pat;
    },
    //车速和总阻力功率的对应关系
    putPU(u, cda, s) {
      let p = (this.putPatU(cda, u) + this.putPrrPwbU(u) + this.putPpeSU(s, u)) / this.form.ec;
      return p;
    },
    //输出一定齿比条件下的，踏频-车速数据
    putRPMUData(i) {
      let data = [];
      for (let u = Math.round(this.putUMin(i) * 10) / 10; u <= Math.round(this.putUMax(i) * 10) / 10; u += 0.1) {
        data.push([Math.round(u * 10) / 10, Math.round(this.putRPMU(u, i) * 10) / 10]);
      }
      return data;
    },
    //输出一定齿比条件下的，与坡度有关的，功率-踏频(车速)数据
    putPSURPMData(i, s) {
      let data = [];
      for (let rpm = 10; rpm <= this.maxRPM; rpm += 1) {
        data.push([rpm, Math.round(this.putURPM(rpm, i) * 10) / 10, Math.round(this.putPRPM(i, s, rpm))]);
      }
      return data;
    },
    //输出功率和车速数据
    putPUData(cda, s) {
      let data = [];
      for (let u = 0; u <= 80; u += 0.1) {
        data.push([Math.round(u * 10) / 10, Math.round(this.putPU(Math.round(u * 10) / 10, cda, s) * 10) / 10]);
      }
      return data;
    },
    //输出滚动阻力和车速数据
    putPrrPwbUData() {
      let data = [];
      for (let u = 0; u <= 80; u += 0.1) {
        data.push([Math.round(u * 10) / 10, Math.round(this.putPrrPwbU(Math.round(u * 10) / 10) * 10) / 10]);
      }
      return data;
    },


    //响应式dom
    resDiv() {
      this.RPMUChart.resize({ width: document.querySelector("#res-div").offsetWidth })
      this.ratioChart.resize({ width: document.querySelector("#res-div").offsetWidth })
      this.PSChart.resize({ width: document.querySelector("#res-div").offsetWidth })
      this.PUChart.resize({ width: document.querySelector("#res-div").offsetWidth })
    },

    //设置main的padding
    resPadding() {
      if (document.body.offsetWidth < 400) {
        document.querySelector('#main').style.padding = '5px';
      } else {
        document.querySelector('#main').style.padding = '20px';
      }
    },

    //设置抽屉的响应式
    drawerWidth() {
      if (document.body.offsetWidth < 600) {
        return document.body.offsetWidth + 'px';
      }
      return 600 + 'px';
    },

    //解析md文件
    parseMd() {
      this.$axios.get('./info.md').then(res => {
        this.html = marked.parse(res.data)
      });
    }

  },
  mounted() {
    this.slopeArr2Fun();
    // 基于准备好的dom，初始化echarts实例
    this.ratioChart = this.$echarts.init(document.querySelector('#ratio-chart'))
    this.RPMUChart = this.$echarts.init(document.querySelector('#rpm-u-chart'))
    this.PSChart = this.$echarts.init(document.querySelector('#p-s-chart'))
    this.PUChart = this.$echarts.init(document.querySelector('#p-u-chart'))


    this.resPadding();
    this.resDiv();

    window.addEventListener("resize", this.resPadding);
    window.addEventListener("resize", this.resDiv);
    this.parseMd()


  },


}

</script>


